#!/usr/bin/env bash

if [[ "${BASH_SOURCE[0]}" == "$0" ]]; then
    echo "This file cannot be run directly. It must be sourced by another script."
    exit 1
fi

REPO="Gcenx/macOS_Wine_builds"
API_URL="https://api.github.com/repos/$REPO/releases?per_page=100"

###############################################
# Fetch all releases + assets
###############################################
fetch_releases() {
    wget -qO- "$API_URL"
}

###############################################
# Find latest stable Wine tarball
###############################################
find_latest_stable() {
    echo "Fetching release list..." >&2

    json=$(fetch_releases)

    versions=$(echo "$json" | jq -r '
        .[] |
        select(.assets[]?.name | test("^wine-stable-[0-9._]+-osx64\\.tar\\.xz$")) |
        .tag_name
    ')

    if [[ -z "$versions" ]]; then
        echo "❌ No stable Wine releases found" >&2
        exit 1
    fi

    latest=$(echo "$versions" | sort -V | tail -n1)

    wine_asset=$(echo "$json" | jq -r "
        .[] | select(.tag_name == \"$latest\") |
        .assets[]? |
        select(.name | test(\"^wine-stable-[0-9._]+-osx64\\\\.tar\\\\.xz$\")) |
        .name
    ")

    digest=$(echo "$json" | jq -r "
        .[] | select(.tag_name == \"$latest\") |
        .assets[]? |
        select(.name == \"$wine_asset\") |
        .digest // empty
    ")

    echo "$latest|$wine_asset|$digest"
}

###############################################
# Install non-Wine bundle assets
# (launcher, icon, plist) — skipped if already
# present so updates only touch Wine itself
###############################################
install_bundle_assets() {
    local CONTENTS="$1"
    local RES="$CONTENTS/Resources"
    local MACOS="$CONTENTS/MacOS"

    mkdir -p "$RES" "$MACOS"

    ###############################################
    # Swift launcher — compile only if missing
    ###############################################
    if [[ ! -f "$MACOS/pdfxchange" ]]; then
        echo "Compiling Swift launcher..."

        cat > "$TEMP_DIR/launcher.swift" << SWIFT
import Cocoa

let appDir    = Bundle.main.bundleURL.appendingPathComponent("Contents")
let wineBin   = appDir.appendingPathComponent("Resources/wine/bin/wine").path
let targetExe = (NSHomeDirectory() as NSString)
                    .appendingPathComponent(".wine/drive_c/users/$USER/Programs/PDFXChangeEditor/PXCEditor.exe")
SWIFT

        cat >> "$TEMP_DIR/launcher.swift" << 'SWIFT'
func toWinePath(_ path: String) -> String {
    if path.hasPrefix("/") {
        return "Z:" + path.replacingOccurrences(of: "/", with: "\\")
    }
    return path
}

func launch(file: String? = nil) {
    var args = [targetExe]
    if let f = file { args.append(toWinePath(f)) }
    let task = Process()
    task.executableURL = URL(fileURLWithPath: wineBin)
    task.arguments     = args
    try? task.run()
}

class AppDelegate: NSObject, NSApplicationDelegate {
    var handledEvent = false

    func application(_ sender: NSApplication, openFile filename: String) -> Bool {
        handledEvent = true
        launch(file: filename)
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.0) { NSApp.terminate(nil) }
        return true
    }

    func applicationDidFinishLaunching(_ note: Notification) {
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.3) { [self] in
            if !self.handledEvent {
                launch()
                DispatchQueue.main.asyncAfter(deadline: .now() + 1.0) { NSApp.terminate(nil) }
            }
        }
    }
}

let app      = NSApplication.shared
let delegate = AppDelegate()
app.delegate = delegate

if CommandLine.arguments.count > 1 {
    let cliFile = CommandLine.arguments[1]
    delegate.handledEvent = true
    launch(file: cliFile)
    DispatchQueue.main.asyncAfter(deadline: .now() + 1.0) { NSApp.terminate(nil) }
}

app.run()
SWIFT

        swiftc "$TEMP_DIR/launcher.swift" \
            -o "$MACOS/pdfxchange" \
            -framework Cocoa \
            -O 2>&1

        if [[ $? -ne 0 ]]; then
            echo "⚠️  Swift compile failed — falling back to bash launcher."
            echo "   File associations from Finder will NOT work with the bash fallback."
            echo "   Install Xcode Command Line Tools (xcode-select --install) and re-run."

            cat > "$MACOS/pdfxchange" << EOF
#!/bin/bash
# FALLBACK: bash launcher — Finder file open (Apple Events) will NOT work.
# Recompile with Swift for full file-association support.
TARGET="\$HOME/.wine/drive_c/users/$USER/Programs/PDFXChangeEditor/PXCEditor.exe"
EOF

            cat >> "$MACOS/pdfxchange" << 'EOF'
APP_DIR="$(cd "$(dirname "$0")/.." && pwd)"
WINE_BIN="$APP_DIR/Resources/wine/bin/wine"

to_wine_path() {
    local p="$1"
    [[ "$p" == /* ]] && echo "Z:${p//\//\\}" || echo "$p"
}

if [[ $# -gt 0 ]]; then
    "$WINE_BIN" "$TARGET" "$(to_wine_path "$1")"
else
    "$WINE_BIN" "$TARGET"
fi
EOF
            chmod +x "$MACOS/pdfxchange"
        fi
    else
        echo "Launcher already present, skipping compile"
    fi

    ###############################################
    # Embedded icon — write only if missing
    ###############################################
    if [[ ! -f "$RES/AppIcon.icns" ]]; then
        echo "Writing icon..."
        read -r -d '' ICON_B64 << 'EOF'

EOF
        echo "$ICON_B64" | base64 --decode > "$RES/AppIcon.icns"
    fi

    ###############################################
    # Info.plist — write only if missing
    ###############################################
    if [[ ! -f "$CONTENTS/Info.plist" ]]; then
        echo "Writing Info.plist..."
        cat > "$CONTENTS/Info.plist" << 'EOF'
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
    <key>CFBundleName</key><string>PDFXChange</string>
    <key>CFBundleIdentifier</key><string>com.example.pdfxchange</string>
    <key>CFBundleExecutable</key><string>pdfxchange</string>
    <key>CFBundlePackageType</key><string>APPL</string>
    <key>CFBundleIconFile</key><string>AppIcon</string>

    <key>CFBundleDocumentTypes</key>
    <array>
        <dict>
            <key>CFBundleTypeName</key><string>PDF Document</string>
            <key>CFBundleTypeRole</key><string>Editor</string>

            <key>LSItemContentTypes</key>
            <array><string>com.adobe.pdf</string></array>

            <key>CFBundleTypeExtensions</key>
            <array><string>pdf</string></array>

            <key>LSTypeIsPackage</key><false/>

            <key>LSHandlerRank</key><string>Owner</string>
        </dict>
    </array>
</dict>
</plist>
EOF
    fi
}

###############################################
# Update Wine bundle + build PDFXChange.app
###############################################
update_wine_bundle() {
    APP="/Applications/PDFXChange.app"
    CONTENTS="$APP/Contents"
    RES="$CONTENTS/Resources"
    VERSION_FILE="$CONTENTS/version.txt"

    match=$(find_latest_stable)
    latest=$(echo "$match" | cut -d '|' -f1)
    wine_asset=$(echo "$match" | cut -d '|' -f2)
    digest=$(echo "$match" | cut -d '|' -f3)

    if [[ -f "$VERSION_FILE" ]]; then
        current=$(cat "$VERSION_FILE")
    else
        current="0"
    fi

    if [[ "$latest" == "$current" ]]; then
        echo "Already up to date (version $current)"
        # Still ensure all bundle assets exist in case this is a repair run
        install_bundle_assets "$CONTENTS"
        return
    fi

    if [[ -z "$digest" ]]; then
        echo "❌ GitHub API did not provide a digest for $wine_asset"
        exit 1
    fi

    echo "Updating from $current → $latest"
    check_processes "wine" "wineserver"
    
    echo "Downloading Wine bundle: $wine_asset"
    gh release download "$latest" --repo "$REPO" --pattern "$wine_asset" --dir "$TEMP_DIR"

    downloaded_tar=$(ls "$TEMP_DIR" | grep -E '\.tar\.xz$' | head -n1)
    WINE_TAR="$TEMP_DIR/$downloaded_tar"

    digest_value="${digest#sha256:}"

    echo "Verifying SHA256..."
    actual=$(shasum -a 256 "$WINE_TAR" | awk '{print $1}')

    if [[ "$actual" != "$digest_value" ]]; then
        echo "❌ Hash mismatch!"
        echo "Expected: $digest_value"
        echo "Actual:   $actual"
        exit 1
    fi

    echo "Extracting Wine..."
    tar -xJf "$WINE_TAR" -C "$TEMP_DIR"

    wine_app_dir=$(find "$TEMP_DIR" -maxdepth 1 -type d -name "Wine*.app" | head -n1)

    if [[ -z "$wine_app_dir" ]]; then
        echo "❌ No Wine*.app found in extracted archive"
        exit 1
    fi

    if [[ ! -d "$wine_app_dir/Contents/Resources/wine" ]]; then
        echo "❌ Wine*.app does not contain Resources/wine"
        exit 1
    fi

    # Install launcher, icon, plist — skipped if already present
    install_bundle_assets "$CONTENTS"

    # Replace only the Wine directory, leaving everything else intact
    echo "Replacing Wine directory..."
    rm -rf "$RES/wine"
    mv "$wine_app_dir/Contents/Resources/wine" "$RES/wine"

    echo "$latest" > "$VERSION_FILE"

    ###############################################
    # Refresh Launch Services so macOS picks up
    # the new bundle immediately
    ###############################################
    echo "Refreshing Launch Services database..."
    /System/Library/Frameworks/CoreServices.framework/Frameworks/LaunchServices.framework/Support/lsregister \
        -f "$APP" 2>/dev/null || true

    echo "✅ Installed Wine bundle version $latest"
}